}

/* ───── Step Indicator ───── */

.step-indicator {
    display: flex;
    align-items: center;
    gap: 0;
    flex-wrap: wrap;
}

.step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    padding: 0.5rem 0.75rem;
    font-size: 0.875rem;
    cursor: default;
    white-space: nowrap;
}

.step.active {
    color: #0d6efd;
    font-weight: 600;
}

.step.active .step-number {
    background: #0d6efd;
    color: #fff;
}

.step.completed {
    color: #198754;
    cursor: pointer;
}

.step.completed .step-number {
    background: #198754;
    color: #fff;
}

.step.dimmed {
    color: #adb5bd;
}

.step.dimmed .step-number {
    background: #dee2e6;
    color: #6c757d;
}

.step-number {
    display: inline-flex;
