{"file_text": ".apply-container {
    max-width: 800px;
    margin: 0 auto;
}

/* ───── Step Indicator ───── */

.step-indicator {
    display: flex;
    align-items: center;
    gap: 0;
    flex-wrap: wrap;
}

.step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    padding: 0.5rem 0.75rem;
    font-size: 0.875rem;
    cursor: default;
    white-space: nowrap;
}

.step.active {
    color: #0d6efd;
    font-weight: 600;
}

.step.active .step-number {
    background: #0d6efd;
    color: #fff;
}

.step.completed {
    color: #198754;
    cursor: pointer;
}

.step.completed .step-number {
    background: #198754;
    color: #fff;
}

.step.dimmed {
    color: #adb5bd;
}

.step.dimmed .step-number {
    background: #dee2e6;
    color: #6c757d;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.75rem;
    height: 1.75rem;
    border-radius: 50%;
    font-size: 0.8rem;
    font-weight: 700;
    flex-shrink: 0;
}

.step-connector {
    flex: 0 0 1.5rem;
    height: 2px;
    background: #dee2e6;
}

/* ───── Review section dividers ───── */

.review-section {
    border-bottom: 1px solid #dee2e6;
    padding-bottom: 0.75rem;
}

.review-section:last-of-type {
    border-bottom: none;
}
