@page "/apply"
@rendermode InteractiveServer
@using sv_18d4a55fbe5543ff89ef10a3252f28bf.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="step-indicator mb-4" aria-label="Application steps">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var step = i;
            var css = step == _currentStep ? "step active"
                    : _completedSteps.Contains(step) ? "step completed"
                    : "step dimmed";

            <button class="@css"
                    disabled="@(!_completedSteps.Contains(step) && step != _currentStep)"
                    @onclick="() => GoToStep(step)">
                <span class="step-number">
                    @if (_completedSteps.Contains(step))
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@_stepLabels[step]</span>
            </button>

            @if (step < _stepLabels.Length - 1)
            {
                <span class="step-connector"></span>
            }
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @* ───── Step 1: Personal Info ───── *@
    @if (_currentStep == 0)
    {
        <div class="card p-4">
            <h4>Personal Information</h4>
            <div class="mb-3">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="_fullName" @bind:event="oninput" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="_email" @bind:event="oninput" />
            </div>
            <div class="mb-3">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput"></textarea>
            </div>
            <div class="d-flex justify-content-end">
                <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isValidating">
                    @if (_isValidating)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Next
                </button>
            </div>
        </div>
    }

    @* ───── Step 2: Work History ───── *@
    @if (_currentStep == 1)
    {
        <div class="card p-4">
            <h4>Work History</h4>
            @for (int i = 0; i < _workEntries.Count; i++)
            {
                var idx = i;
                <div class="border rounded p-3 mb-3 position-relative">
                    <h6>Position @(idx + 1)</h6>
                    @if (_workEntries.Count > 1)
                    {
                        <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                    }
                    <div class="row mb-2">
                        <div class="col-md-6">
                            <label class="form-label">Company <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="_workEntries[idx].Company" @bind:event="oninput" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Job Title <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="_workEntries[idx].Title" @bind:event="oninput" />
                        </div>
                    </div>
                    <div class="row mb-2">
                        <div class="col-md-4">
                            <label class="form-label">Start Date <span class="text-danger">*</span></label>
                            <input type="date" class="form-control" @bind="_workEntries[idx].StartDate" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">End Date</label>
                            <input type="date" class="form-control" @bind="_workEntries[idx].EndDate"
                                   disabled="@_workEntries[idx].IsCurrent" />
                        </div>
                        <div class="col-md-4 d-flex align-items-end mb-1">
                            <div class="form-check">
                                <input type="checkbox" class="form-check-input" id="@($"current-{idx}")"
                                       @bind="_workEntries[idx].IsCurrent" />
                                <label class="form-check-label" for="@($"current-{idx}")">Currently working here</label>
                            </div>
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <textarea class="form-control" rows="2" @bind="_workEntries[idx].Description" @bind:event="oninput"></textarea>
                    </div>
                </div>
            }
            <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
            </div>
        </div>
    }

    @* ───── Step 3: References ───── *@
    @if (_currentStep == 2)
    {
        <div class="card p-4">
            <h4>References</h4>
            @for (int i = 0; i < _references.Count; i++)
            {
                var idx = i;
                <div class="border rounded p-3 mb-3 position-relative">
                    <h6>Reference @(idx + 1)</h6>
                    @if (_references.Count > 2)
                    {
                        <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                @onclick="() => RemoveReference(idx)">Remove</button>
                    }
                    <div class="row mb-2">
                        <div class="col-md-6">
                            <label class="form-label">Name <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="_references[idx].Name" @bind:event="oninput" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Relationship <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="_references[idx].Relationship" @bind:event="oninput" />
                        </div>
                    </div>
                    <div class="row mb-2">
                        <div class="col-md-6">
                            <label class="form-label">Email <span class="text-danger">*</span></label>
                            <input type="email" class="form-control" @bind="_references[idx].Email" @bind:event="oninput" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Phone <span class="text-danger">*</span></label>
                            <input type="tel" class="form-control" @bind="_references[idx].Phone" @bind:event="oninput" />
                        </div>
                    </div>
                </div>
            }
            @if (_references.Count < 3)
            {
                <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
            }
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
            </div>
        </div>
    }

    @* ───── Step 4: Cover Letter ───── *@
    @if (_currentStep == 3)
    {
        <div class="card p-4">
            <h4>Cover Letter</h4>
            <div class="mb-3">
                <textarea class="form-control" rows="10" maxlength="2000"
                          @bind="_coverLetter" @bind:event="oninput"></textarea>
                <div class="form-text text-end">@(_coverLetter.Length) / 2000 characters</div>
            </div>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="Back">Back</button>
                <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
            </div>
        </div>
    }

    @* ───── Step 5: Review & Submit ───── *@
    @if (_currentStep == 4)
    {
        @if (_submitted)
        {
            <div class="card p-4 text-center">
                <h4 class="text-success">&#10003; Application Submitted!</h4>
                <p class="fs-5">Your application ID is <strong>@_applicationId</strong></p>
                <p>Thank you for applying. We will be in touch.</p>
            </div>
        }
        else
        {
            <div class="card p-4">
                <h4>Review &amp; Submit</h4>

                @* Personal Info Summary *@
                <div class="review-section mb-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Personal Information</h5>
                        <button class="btn btn-sm btn-link" @onclick="() => GoToStep(0)">Edit</button>
                    </div>
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>

                @* Work History Summary *@
                <div class="review-section mb-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Work History</h5>
                        <button class="btn btn-sm btn-link" @onclick="() => GoToStep(1)">Edit</button>
                    </div>
                    @foreach (var entry in _workEntries)
                    {
                        <div class="border-start border-3 ps-3 mb-2">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <small class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") &ndash;
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                            </small>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mb-0 mt-1">@entry.Description</p>
                            }
                        </div>
                    }
                </div>

                @* References Summary *@
                <div class="review-section mb-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>References</h5>
                        <button class="btn btn-sm btn-link" @onclick="() => GoToStep(2)">Edit</button>
                    </div>
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> (@r.Relationship)<br />
                            <small>@r.Email &middot; @r.Phone</small>
                        </div>
                    }
                </div>

                @* Cover Letter Summary *@
                <div class="review-section mb-3">
                    <div class="d-flex justify-content-between align-items-center">
                        <h5>Cover Letter</h5>
                        <button class="btn btn-sm btn-link" @onclick="() => GoToStep(3)">Edit</button>
                    </div>
                    <p style="white-space: pre-wrap;">@_coverLetter</p>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
                        @if (_isSubmitting)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Submit Application
                    </button>
                </div>
            </div>
        }
    }
</div>

@code {
    private const int TotalSteps = 5;
    private static readonly string[] _stepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();
    private string _errorMessage = string.Empty;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;
    private bool _isValidating;

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new() };

    // Step 3
    private List<ReferenceModel> _references = new() { new(), new() };

    // Step 4
    private string _coverLetter = string.Empty;

    // Step 5
    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;

    // ───── Navigation ─────

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
        {
            _errorMessage = string.Empty;
            _currentStep = step;
        }
    }

    private void Back()
    {
        _errorMessage = string.Empty;
        if (_currentStep > 0) _currentStep--;
    }

    private void AdvanceTo(int step)
    {
        _completedSteps.Add(_currentStep);
        _errorMessage = string.Empty;
        _currentStep = step;
    }

    // ───── Step 1 Validation ─────

    private async Task NextFromPersonalInfo()
    {
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "Please fill in all required fields.";
            return;
        }

        _isValidating = true;
        _errorMessage = string.Empty;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
            AdvanceTo(1);
        }
        finally
        {
            _isValidating = false;
        }
    }

    // ───── Step 2 ─────

    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
    }

    private void NextFromWorkHistory()
    {
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default)
            {
                _errorMessage = "Please fill in company, job title, and start date for each position.";
                return;
            }
        }
        AdvanceTo(2);
    }

    // ───── Step 3 ─────

    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2) _references.RemoveAt(index);
    }

    private void NextFromReferences()
    {
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        AdvanceTo(3);
    }

    // ───── Step 4 ─────

    private void NextFromCoverLetter()
    {
        AdvanceTo(4);
    }

    // ───── Step 5 ─────

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = string.Empty;
        try
        {
            var application = BuildApplication();
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch
        {
            _errorMessage = "Submission failed. Please try again.";
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private JobApplication BuildApplication()
    {
        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
        var work = new WorkHistory(_workEntries.Select(e =>
            new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
        var refs = _references.Select(r =>
            new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
        return new JobApplication(personal, work, refs, _coverLetter);
    }

    // ───── Mutable view-models for two-way binding ─────

    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

